(535, 'zipwp_user_business_details', 'a:14:{s:20:\"business_description\";s:267:\"X Learning is a non-profit organization dedicated to providing accessible online courses for all learners. Our platform offers a diverse range of educational resources, promoting lifelong learning and empowering individuals to achieve their academic and career goals.\";s:13:\"business_name\";s:10:\"X Learning\";s:14:\"business_email\";s:20:\"bacxnt2005@gmail.com\";s:16:\"business_address\";s:20:\"bacxnt2005@gmail.com\";s:14:\"business_phone\";s:10:\"0838177205\";s:17:\"business_category\";s:10:\"Non-profit\";s:22:\"business_category_name\";s:10:\"Non-profit\";s:13:\"image_keyword\";a:5:{i:0;s:14:\"online courses\";i:1;s:21:\"educational resources\";i:2;s:17:\"lifelong learning\";i:3;s:11:\"empowerment\";i:4;s:14:\"academic goals\";}s:6:\"images\";a:18:{i:0;a:11:{s:2:\"id\";s:7:\"6238297\";s:3:\"url\";s:73:\"https://images.pexels.com/photos/6238297/pexels-photo-6238297.jpeg?w=1280\";s:13:\"optimized_url\";s:98:\"https://images.pexels.com/photos/6238297/pexels-photo-6238297.jpeg?auto=compress&cs=tinysrgb&h=350\";s:11:\"description\";s:87:\"Close-up of hand writing complex math equations on a chalkboard in a classroom setting.\";s:10:\"author_url\";s:31:\"https://www.pexels.com/@gabby-k\";s:11:\"author_name\";s:19:\"Monstera Production\";s:11:\"orientation\";s:9:\"landscape\";s:6:\"engine\";s:6:\"pexels\";s:10:\"engine_url\";s:18:\"https://pexels.com\";s:4:\"slug\";s:39:\"equations-written-on-blackboard-6238297\";s:17:\"download_location\";s:0:\"\";}i:1;a:11:{s:2:\"id\";s:7:\"8482035\";s:3:\"url\";s:73:\"https://images.pexels.com/photos/8482035/pexels-photo-8482035.jpeg?w=1280\";s:13:\"optimized_url\";s:98:\"https://images.pexels.com/photos/8482035/pexels-photo-8482035.jpeg?auto=compress&cs=tinysrgb&h=350\";s:11:\"description\";s:88:\"Close-up of a parabola graph on paper with pencil, perfect for math or education themes.\";s:10:\"author_url\";s:29:\"https://www.pexels.com/@19x14\";s:11:\