":\"eb224300\",\"classMigrate\":true,\"headingDescToggle\":true,\"subHeadingColor\":\"\",\"headSpace\":10,\"subHeadSpace\":0,\"blockTopPadding\":48,\"blockRightPadding\":0,\"blockLeftPadding\":48,\"blockBottomPadding\":0,\"blockTopPaddingTablet\":40,\"blockRightPaddingTablet\":20,\"blockLeftPaddingTablet\":20,\"blockBottomPaddingTablet\":0,\"blockTopPaddingMobile\":0,\"blockRightPaddingMobile\":0,\"blockLeftPaddingMobile\":0,\"blockBottomPaddingMobile\":0,\"blockTopMargin\":-100,\"blockRightMargin\":0,\"blockLeftMargin\":0,\"blockBottomMargin\":0,\"blockTopMarginTablet\":-80,\"blockRightMarginTablet\":0,\"blockLeftMarginTablet\":0,\"blockBottomMarginTablet\":0,\"blockTopMarginMobile\":0,\"blockRightMarginMobile\":0,\"blockLeftMarginMobile\":0,\"blockBottomMarginMobile\":0} -->\n<div class=\"wp-block-uagb-advanced-heading uagb-block-eb224300\"><h2 class=\"uagb-heading-text\">Lịch Sử Hình Thành và Phát Triển Của Chúng Tôi</h2><p class=\"uagb-desc-text\">X Learning ra đời với sứ mệnh tạo điều kiện cho mọi người tiếp cận học tập. Từ những ngày đầu khó khăn, chúng tôi đã không ngừng phát triển và mở rộng, đem đến những khóa học phong phú và đa dạng. Đến nay, X Learning đã trở thành một trong những nền tảng hàng đầu cho giáo dục trực tuyến, phục vụ hàng triệu học viên trên toàn cầu.</p></div>\n<!-- /wp:uagb/advanced-heading --></div></div>\n<!-- /wp:uagb/container -->\n\n<!-- wp:block {\"ref\":597} /-->', 'About', '', 'inherit', 'closed', 'closed', '', '290-revision-v1', '', '', '2026-04-13 07:03:15', '2026-04-13 07:03:15', '', 290, 'http://localhost/wp_bacxje/?p=640', 0, 'revision', '', 0);
