rator uagb-block-f5959e00\"><div class=\"uagb-separator-spacing-wrapper\"><div class=\"wp-block-uagb-separator__inner\" style=\"--my-background-image:\"></div></div></div>\n<!-- /wp:uagb/separator -->\n\n<!-- wp:uagb/advanced-heading {\"block_id\":\"77d24e2b\",\"classMigrate\":true,\"headingDescToggle\":false,\"blockTopPadding\":0,\"blockRightPadding\":80,\"blockLeftPadding\":0,\"blockBottomPadding\":0,\"blockTopPaddingMobile\":0,\"blockRightPaddingMobile\":0,\"blockLeftPaddingMobile\":0,\"blockBottomPaddingMobile\":0} -->\n<div class=\"wp-block-uagb-advanced-heading uagb-block-77d24e2b\"><h2 class=\"uagb-heading-text\">Về X Learning - Đối Tác Giáo Dục Của Bạn</h2></div>\n<!-- /wp:uagb/advanced-heading -->\n\n<!-- wp:uagb/container {\"block_id\":\"2fe8b1bc\",\"topPaddingTablet\":0,\"bottomPaddingTablet\":0,\"leftPaddingTablet\":56,\"rightPaddingTablet\":0,\"topPaddingMobile\":0,\"bottomPaddingMobile\":0,\"leftPaddingMobile\":0,\"rightPaddingMobile\":0,\"paddingLink\":false,\"rowGapDesktop\":36,\"rowGapTablet\":24,\"rowGapMobile\":24,\"isGridCssInParent\":true,\"gridColumnSpanTablet\":2} -->\n<div class=\"wp-block-uagb-container uagb-block-2fe8b1bc\"><!-- wp:uagb/advanced-heading {\"block_id\":\"10f5d053\",\"classMigrate\":true,\"headingDescToggle\":true,\"headingColor\":\"var(--ast-global-color-3)\",\"subHeadingColor\":\"\",\"headingTag\":\"p\",\"headSpace\":10,\"subHeadSpace\":0} -->\n<div class=\"wp-block-uagb-advanced-heading uagb-block-10f5d053\"><p class=\"uagb-heading-text\">X Learning là một tổ chức phi lợi nhuận, cam kết cung cấp các khóa học trực tuyến dễ tiếp cận cho tất cả mọi người. Nền tảng của chúng tôi mang đến một loạt các nguồn tài nguyên giáo dục, khuyến khích việc học suốt đời và giúp cá nhân đạt được mục tiêu học thuật và nghề nghiệp.</p><p class=\"uagb-desc-text\">Chúng tôi đã giúp hàng nghìn học viên đạt được thành công trong học tập và nghề nghiệp.</p></div>\n<!-- /wp:uagb/advanced-heading -->\n\n<!-- wp:uagb/image {\"block_id\":\"d72ff795\",\